async def generate_with_retry(client, messages, max_retries=2):
    for attempt in range(max_retries + 1):
        response = await client.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            system=OUTPUT_FORMAT_INSTRUCTION,
            messages=messages,
        )
        text = response.content[0].text
        errors = validate_markdown(text)
        if not errors:
            return text

        if attempt < max_retries:
            error_summary = "\n".join(f"- {e}" for e in errors)
            messages = messages + [
                {"role": "assistant", "content": text},
                {
                    "role": "user",
                    "content": (
                        f"Your previous response had formatting errors:\n{error_summary}\n"
                        "Please correct these issues and reproduce the full document."
                    ),
                },
            ]

    raise ValueError(f"Markdown validation failed after {max_retries + 1} attempts: {errors}")

import mistune
import smtplib
from email.mime.multipart import MIMEMultipart
from email.mime.text import MIMEText

def route_markdown(md_text: str, consumers: list[str]) -> dict:
    results = {}

    if "web" in consumers:
        html = mistune.create_markdown(
            plugins=["table", "strikethrough", "task_lists"]
        )(md_text)
        results["web_html"] = html

    if "email" in consumers:
        # Dual-part MIME: HTML + plain-text fallback
        msg = MIMEMultipart("alternative")
        msg.attach(MIMEText(md_text, "plain"))
        msg.attach(MIMEText(mistune.html(md_text), "html"))
        results["email_mime"] = msg

    if "log" in consumers:
        results["raw_markdown"] = md_text

    return results

