import { marked } from "marked";
import DOMPurify from "isomorphic-dompurify";

export function renderAgentMarkdown(md) {
  const rawHtml = marked.parse(md, { gfm: true, breaks: false });
  return DOMPurify.sanitize(rawHtml);   // strip any injected <script> tags
}

import mistune
import bleach

ALLOWED_TAGS = bleach.sanitizer.ALLOWED_TAGS | {
    "p", "h2", "h3", "h4", "pre", "code", "table",
    "thead", "tbody", "tr", "th", "td", "blockquote",
}
ALLOWED_ATTRS = {**bleach.sanitizer.ALLOWED_ATTRIBUTES, "code": ["class"], "a": ["href"]}

def safe_render(md_text: str) -> str:
    """Convert Markdown to HTML with XSS protection."""
    # Step 1: parse with HTML escape ON
    renderer = mistune.HTMLRenderer(escape=True)
    md = mistune.create_markdown(renderer=renderer, plugins=["table", "strikethrough"])
    html = md(md_text)
    # Step 2: sanitize the HTML output
    return bleach.clean(html, tags=ALLOWED_TAGS, attributes=ALLOWED_ATTRS, strip=True)
